16	//
17	// RBTDRP — pristine-lifecycle fixture for theurge release qualification
18	//
19	// Case 1 (marshal-zero-attestation) is the entry gate for `rbw-tP`. It asserts
20	// that the working tree was just zeroed by `rbw-MZ` (rblm_zero) — five
21	// violation classes are checked and ALL surfaced in one aggregated diagnostic.
22	// Failure short-circuits subsequent cases via the per-fixture fail_fast switch.
23	
24	use std::path::{Path, PathBuf};
25	use std::process::Command;
26	
27	use crate::case;
28	use crate::rbtdrc_crucible::rbtdrc_with_ctx;
29	use crate::rbtdre_engine::{rbtdre_Section, rbtdre_Verdict};
30	use crate::rbtdri_invocation::{
31	    rbtdri_invoke_global, rbtdri_invoke_imprint, rbtdri_read_burv_fact, rbtdri_Context,
32	    RBTDRI_BURV_OUTPUT_SUBDIR,
33	};
34	use crate::rbtdrm_manifest::{
35	    RBTDRM_COLOPHON_ACCESS_PROBE, RBTDRM_COLOPHON_DEPOT_LEVY, RBTDRM_COLOPHON_DEPOT_LIST,
36	    RBTDRM_COLOPHON_DEPOT_UNMAKE, RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
37	    RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER, RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
38	    RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER, RBTDRM_COLOPHON_GOV_MANTLE,
39	};
40	
41	/// RBRR field names referenced by the pristine-lifecycle fixture. Field
42	/// identifiers extracted as consts so the blank-field array and the
43	/// throwaway-prefix install helper share a single definition site.
44	const RBTDRP_FIELD_RBRR_CLOUD_PREFIX: &str = "RBRR_CLOUD_PREFIX";
45	const RBTDRP_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
46	const RBTDRP_FIELD_RBRR_DEPOT_MONIKER: &str = "RBRR_DEPOT_MONIKER";
47	
48	/// Site-specific RBRR fields that rblm_zero blanks. These three fields define
49	/// the depot-bound site identity (project ID, GAR repo, pool stem, and bucket
50	/// derive from CLOUD_PREFIX + DEPOT_MONIKER at kindle); an empty value is the
51	/// post-marshal-zero invariant.
52	const RBTDRP_RBRR_BLANK_FIELDS: &[&str] = &[
53	    RBTDRP_FIELD_RBRR_CLOUD_PREFIX,
54	    RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
55	    RBTDRP_FIELD_RBRR_DEPOT_MONIKER,
56	];
57	
58	/// Throwaway RBRR prefix values stamped into rbrr.env by
59	/// `rbtdrp_install_throwaway_prefixes`. Pristine-lifecycle cases that need
60	/// non-blank prefixes (depot/governor/retriever/director lifecycle) call the
61	/// helper to install these values; the marker shape distinguishes throwaway
62	/// from operator-chosen canonical values.
63	pub(crate) const RBTDRP_THROWAWAY_CLOUD_PREFIX: &str = "prlc-";
64	pub(crate) const RBTDRP_THROWAWAY_RUNTIME_PREFIX: &str = "prlr-";
65	
66	/// Family stem for the fused arc section. One depot shared across all three
67	/// arc cases; the stem keeps arc monikers separable from other fixture
68	/// families. Cases pick a numeric six-digit suffix at runtime by walking
69	/// emitted depot fact files and incrementing past the highest existing
70	/// suffix per family.
71	const RBTDRP_FAMILY_STEM_ARC: &str = "pristl";
72	
73	/// Static identities for the SA cycle case. The invest colophons compose
74	/// SA account names as `<role>-<identity>`; these are stable across runs
75	/// because each run uses a fresh throwaway depot project.
76	const RBTDRP_IDENTITY_RETRIEVER: &str = "pristl-ret";
77	const RBTDRP_IDENTITY_DIRECTOR: &str = "pristl-dir";
78	
79	/// Lowest valid numeric suffix for autodetected monikers. Six-digit width
80	/// keeps composed project_id length predictable: cloud_prefix(<=11) +
81	/// "d-"(2) + family(6) + suffix(6) = <=25, well under the 30-char GCP limit.
82	const RBTDRP_FAMILY_NUMERIC_FLOOR: u32 = 100000;
83	
84	/// Six-digit numeric suffix width — enforced when parsing existing fact-file
85	/// names so e.g. "pristq01" (legacy two-digit) is ignored rather than parsed
86	/// as 1 and shadowing real entries.
87	const RBTDRP_FAMILY_NUMERIC_WIDTH: usize = 6;
88	
89	/// Fact-file extension mirror of RBCC_fact_ext_depot in rbcc_Constants.sh.
90	/// rbgp_depot_list emits `<moniker>.depot` files with state content.
91	const RBTDRP_FACT_EXT_DEPOT: &str = "depot";
92	
93	/// Fact-file extension mirror of RBCC_fact_ext_depot_project in
94	/// rbcc_Constants.sh. rbgp_depot_list emits `<moniker>.depot-project` files
95	/// with project_id content.
96	const RBTDRP_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
97	
98	/// Fact-file name for the governor SA email (mirror of
99	/// RBGP_FACT_GOVERNOR_SA_EMAIL from rbgc_Constants.sh). Read from the mantle
100	/// invocation's BURV output.
101	const RBTDRP_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
102	
103	/// BURE confirmation override (mirrors buc_command.sh): when set to "skip",
104	/// `buc_require` accepts the operation without interactive prompt.
105	const RBTDRP_BURE_CONFIRM_KEY: &str = "BURE_CONFIRM";
106	const RBTDRP_BURE_CONFIRM_SKIP: &str = "skip";
107	
108	/// `DELETE_REQUESTED` lifecycle state — appears in `rbgp_depot_list` output
109	/// after a soft-delete, used by case 2 to relax the post-unmake assertion.
110	const RBTDRP_DELETE_REQUESTED: &str = "DELETE_REQUESTED";
111	
112	/// Roles whose RBRA credential files rblm_zero deletes.
113	const RBTDRP_RBRA_ROLES: &[&str] = &["governor", "director", "retriever", "assay"];
114	
115	/// Nameplate hallmark fields rblm_zero blanks.
116	const RBTDRP_RBRN_BLANK_FIELDS: &[&str] = &["RBRN_SENTRY_HALLMARK", "RBRN_BOTTLE_HALLMARK"];
117	
118	/// File-relative constants matching rbbc_constants.sh / rbcc_Constants.sh.
119	const RBTDRP_DOT_DIR: &str = ".rbk";
120	const RBTDRP_RBRR_FILE: &str = ".rbk/rbrr.env";
121	const RBTDRP_RBRA_FILE: &str = "rbra.env";
122	const RBTDRP_RBRN_FILE: &str = "rbrn.env";
123	const RBTDRP_RBRV_FILE: &str = "rbrv.env";
124	
125	// ── Helpers ──────────────────────────────────────────────────
126	
127	/// Read an env file and return the value for `key`, or None if the key is
128	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
129	/// and blank lines are skipped. The trailing newline is stripped from value.
130	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
131	    let content = std::fs::read_to_string(path).ok()?;
132	    let prefix = format!("{}=", key);
133	    for line in content.lines() {
134	        let trimmed = line.trim_start();
135	        if trimmed.starts_with('#') {
136	            continue;
137	        }
138	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
139	            return Some(rest.to_string());
140	        }
141	    }
142	    None
143	}
144	
145	/// Resolve a path that may be absolute or relative-to-project-root.
146	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
147	    if Path::new(raw).is_absolute() {
148	        PathBuf::from(raw)
149	    } else {
150	        root.join(raw)
151	    }
152	}
153	
154	/// Class A — working tree clean (`git status --porcelain` empty).
155	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
156	    match Command::new("git")
157	        .args(["status", "--porcelain"])
158	        .current_dir(root)
159	        .output()
160	    {
161	        Ok(out) if out.status.success() => {
162	            let stdout = String::from_utf8_lossy(&out.stdout);
163	            let trimmed = stdout.trim();
164	            if !trimmed.is_empty() {
165	                violations.push(format!(
166	                    "working tree not clean — uncommitted changes:\n{}",
167	                    trimmed
168	                ));
169	            }
170	        }
171	        Ok(out) => violations.push(format!(
172	            "git status --porcelain failed (exit {}): {}",
173	            out.status.code().unwrap_or(-1),
174	            String::from_utf8_lossy(&out.stderr).trim()
175	        )),
176	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
177	    }
178	}
179	
180	/// Class B — five site-specific RBRR fields are blank.
181	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
182	    for field in RBTDRP_RBRR_BLANK_FIELDS {
183	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
184	            if !value.is_empty() {
185	                violations.push(format!(
186	                    "RBRR field non-blank: {}={} (in {})",
187	                    field,
188	                    value,
189	                    rbrr.display()
190	                ));
191	            }
192	        }
193	    }
194	}
195	
196	/// Class C — no RBRA credential files at the four role paths.
197	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
198	    if secrets_dir.is_empty() {
199	        violations.push(
200	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
201	        );
202	        return;
203	    }
204	    let secrets = rbtdrp_resolve(root, secrets_dir);
205	    for role in RBTDRP_RBRA_ROLES {
206	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
207	        if path.exists() {
208	            violations.push(format!("RBRA credential present: {}", path.display()));
209	        }
210	    }
211	}
212	
213	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
214	/// is blank.
215	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
216	    let dot_dir = root.join(RBTDRP_DOT_DIR);
217	    let entries = match std::fs::read_dir(&dot_dir) {
218	        Ok(e) => e,
219	        Err(e) => {
220	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
221	            return;
222	        }
223	    };
224	    for entry in entries.flatten() {
225	        let np_dir = entry.path();
226	        if !np_dir.is_dir() {
227	            continue;
228	        }
229	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
230	        if !rbrn.exists() {
231	            continue;
232	        }
233	        for field in RBTDRP_RBRN_BLANK_FIELDS {
234	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
235	                if !value.is_empty() {
236	                    violations.push(format!(
237	                        "nameplate hallmark non-blank: {}={} (in {})",
238	                        field,
239	                        value,
240	                        rbrn.display()
241	                    ));
242	                }
243	            }
244	        }
245	    }
246	}
247	
248	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
249	/// RBRV_IMAGE_*_ANCHOR field blank.
250	fn rbtdrp_check_vessel_depot_fields(
251	    root: &Path,
252	    vessel_dir: &str,
253	    violations: &mut Vec<String>,
254	) {
255	    if vessel_dir.is_empty() {
256	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
257	        return;
258	    }
259	    let vroot = rbtdrp_resolve(root, vessel_dir);
260	    let entries = match std::fs::read_dir(&vroot) {
261	        Ok(e) => e,
262	        Err(e) => {
263	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
264	            return;
265	        }
266	    };
267	    for entry in entries.flatten() {
268	        let v_dir = entry.path();
269	        if !v_dir.is_dir() {
270	            continue;
271	        }
272	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
273	        if !rbrv.exists() {
274	            continue;
275	        }
276	        rbtdrp_scan_rbrv_file(&rbrv, violations);
277	    }
278	}
279	
280	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
281	/// fields.
282	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
283	    let content = match std::fs::read_to_string(rbrv) {
284	        Ok(c) => c,
285	        Err(e) => {
286	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
287	            return;
288	        }
289	    };
290	    for line in content.lines() {
291	        let trimmed = line.trim_start();
292	        if trimmed.starts_with('#') {
293	            continue;
294	        }
295	        let (key, value) = match trimmed.split_once('=') {
296	            Some(kv) => kv,
297	            None => continue,
298	        };
299	        let is_reliquary = key == "RBRV_RELIQUARY";
300	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
301	        if (is_reliquary || is_anchor) && !value.is_empty() {
302	            violations.push(format!(
303	                "vessel depot-scoped field non-blank: {}={} (in {})",
304	                key,
305	                value,
306	                rbrv.display()
307	            ));
308	        }
309	    }
310	}
311	
312	// ── Env-file rewrite + git commit helpers ────────────────────
313	
314	/// Rewrite each line in `content` whose key matches an entry in `pairs`
315	/// (matched as `KEY=`) to `KEY=value`. Lines whose keys are not in `pairs`
316	/// pass through unchanged. The trailing-newline shape is preserved.
317	fn rbtdrp_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
318	    let mut result: String = content
319	        .lines()
320	        .map(|line| {
321	            for (key, value) in pairs {
322	                let assign = format!("{}=", key);
323	                if line.starts_with(&assign) {
324	                    return format!("{}{}", assign, value);
325	                }
326	            }
327	            line.to_string()
328	        })
329	        .collect::<Vec<_>>()
330	        .join("\n");
331	    if content.ends_with('\n') {
332	        result.push('\n');
333	    }
334	    result
335	}
336	
337	/// `git add <file> && git commit -m <message>` from `root`. Bubbles the
338	/// underlying stderr on either step's failure.
339	fn rbtdrp_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
340	    let add = Command::new("git")
341	        .args(["add", file])
342	        .current_dir(root)
343	        .output()
344	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
345	    if !add.status.success() {
346	        return Err(format!(
347	            "rbtdrp: git add failed (exit {}): {}",
348	            add.status.code().unwrap_or(-1),
349	            String::from_utf8_lossy(&add.stderr).trim()
350	        ));
351	    }
352	
353	    let commit = Command::new("git")
354	        .args(["commit", "-m", message])
355	        .current_dir(root)
356	        .output()
357	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
358	    if !commit.status.success() {
359	        return Err(format!(
360	            "rbtdrp: git commit failed (exit {}): {}",
361	            commit.status.code().unwrap_or(-1),
362	            String::from_utf8_lossy(&commit.stderr).trim()
363	        ));
364	    }
365	
366	    Ok(())
367	}
368	
369	// ── Throwaway-prefix install ─────────────────────────────────
370	
371	/// Idempotently install throwaway RBRR prefixes into `.rbk/rbrr.env`.
372	///
373	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
374	/// retriever/director lifecycle) call this as their first step. The helper
375	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
376	/// already match the throwaway markers, returns `Ok(())` with no side
377	/// effect. Otherwise rewrites both lines in place, then `git add` +
378	/// `git commit` the change. One commit per fixture run regardless of which
379	/// case is the first to call it.
380	///
381	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
382	/// matching the pristine fixture's start-over-from-zero failure mode.
383	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
384	    let rbrr = root.join(RBTDRP_RBRR_FILE);
385	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
386	    let runtime =
387	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
388	
389	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
390	        return Ok(());
391	    }
392	
393	    let content = std::fs::read_to_string(&rbrr)
394	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
395	    let new_content = rbtdrp_replace_env_fields(
396	        &content,
397	        &[
398	            (RBTDRP_FIELD_RBRR_CLOUD_PREFIX, RBTDRP_THROWAWAY_CLOUD_PREFIX),
399	            (
400	                RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
401	                RBTDRP_THROWAWAY_RUNTIME_PREFIX,
402	            ),
403	        ],
404	    );
405	    std::fs::write(&rbrr, &new_content)
406	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
407	
408	    let commit_msg = format!(
409	        "pristine-lifecycle fixture: install throwaway RBRR prefixes ({}/{})",
410	        RBTDRP_THROWAWAY_CLOUD_PREFIX, RBTDRP_THROWAWAY_RUNTIME_PREFIX
411	    );
412	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
413	}
414	
415	/// Pick the next free moniker for `family_stem` by walking the depot_list
416	/// invocation's BURV output dir for `<family>NNNNNN.depot` files, parsing
417	/// the numeric suffix from each, and returning `<family><max + 1>`. Returns
418	/// `<family>RBTDRP_FAMILY_NUMERIC_FLOOR` when no matching files exist or the
419	/// output dir is missing (first run, no prior depots).
420	fn rbtdrp_pick_next_moniker(
421	    list_result: &crate::rbtdri_invocation::rbtdri_InvokeResult,
422	    family_stem: &str,
423	) -> Result<String, String> {
424	    let dir = list_result
425	        .burv_output
426	        .join(crate::rbtdri_invocation::RBTDRI_BURV_OUTPUT_SUBDIR);
427	
428	    let entries = match std::fs::read_dir(&dir) {
429	        Ok(e) => e,
430	        Err(_) => {
431	            return Ok(format!("{}{}", family_stem, RBTDRP_FAMILY_NUMERIC_FLOOR));
432	        }
433	    };
434	
435	    let suffix_ext = format!(".{}", RBTDRP_FACT_EXT_DEPOT);
436	    let mut max_suffix: Option<u32> = None;
437	    for entry in entries.flatten() {
438	        let name = match entry.file_name().into_string() {
439	            Ok(n) => n,
440	            Err(_) => continue,
441	        };
442	        let stem = match name.strip_suffix(&suffix_ext) {
443	            Some(s) => s,
444	            None => continue,
445	        };
446	        let numeric = match stem.strip_prefix(family_stem) {
447	            Some(s) => s,
448	            None => continue,
449	        };
450	        if numeric.len() != RBTDRP_FAMILY_NUMERIC_WIDTH {
451	            continue;
452	        }
453	        let parsed: u32 = match numeric.parse() {
454	            Ok(n) => n,
455	            Err(_) => continue,
456	        };
457	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
458	    }
459	
460	    let next = match max_suffix {
461	        Some(m) => m + 1,
462	        None => RBTDRP_FAMILY_NUMERIC_FLOOR,
463	    };
464	    Ok(format!("{}{}", family_stem, next))
465	}
466	
467	/// Compose the depot project_id from kindled regime values. Mirrors RBDC's
468	/// derivation: `${RBRR_CLOUD_PREFIX}d-${moniker}`. Used by cases 2 and 3 to
469	/// recover the project_id post-levy without re-reading a fact file (the
470	/// pre-collapse `rbgp_fact_depot_project_id` producer is gone).
471	fn rbtdrp_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
472	    let rbrr = root.join(RBTDRP_RBRR_FILE);
473	    let cloud_prefix = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX)
474	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
475	    Ok(format!("{}d-{}", cloud_prefix, moniker))
476	}
