502	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
503	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
504	/// just executed and committed.
505	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
506	    let root = match std::env::current_dir() {
507	        Ok(r) => r,
508	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
509	    };
510	
511	    let rbrr = root.join(RBTDRP_RBRR_FILE);
512	    if !rbrr.exists() {
513	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
514	    }
515	
516	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
517	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
518	
519	    let mut violations: Vec<String> = Vec::new();
520	
521	    rbtdrp_check_tree_clean(&root, &mut violations);
522	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
523	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
524	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
525	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
526	
527	    if violations.is_empty() {
528	        return rbtdre_Verdict::Pass;
529	    }
530	
531	    let body = violations
532	        .iter()
533	        .map(|v| format!("  - {}", v))
534	        .collect::<Vec<_>>()
535	        .join("\n");
536	    rbtdre_Verdict::Fail(format!(
537	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
538	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
539	        violations.len(),
540	        body
541	    ))
542	}
