546	/// Wrapper invocation: call `rbtdri_invoke_global` and tee stdout/stderr to
547	/// `dir/<label>-stdout.txt` / `dir/<label>-stderr.txt` for diagnostic review.
548	/// Returns `Ok(InvokeResult)` regardless of exit code; callers decide what
549	/// counts as failure.
550	fn rbtdrp_invoke_logged(
551	    ctx: &mut rbtdri_Context,
552	    colophon: &str,
553	    args: &[&str],
554	    extra_env: &[(&str, &str)],
555	    dir: &Path,
556	    label: &str,
557	) -> Result<crate::rbtdri_invocation::rbtdri_InvokeResult, String> {
558	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
559	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
560	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
561	    Ok(result)
562	}
