564	/// Resolve the canonical RBRA path for a role by reading RBRR_SECRETS_DIR
565	/// from rbrr.env and joining `<role>/rbra.env`.
566	fn rbtdrp_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
567	    let rbrr = root.join(RBTDRP_RBRR_FILE);
568	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR")
569	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
570	    if secrets_dir.is_empty() {
571	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
572	    }
573	    Ok(rbtdrp_resolve(root, &secrets_dir).join(role).join(RBTDRP_RBRA_FILE))
574	}
