577	
578	/// Case 2 — depot stand-up. Installs throwaway prefixes, picks the next free
579	/// moniker in the `pristl` family, levies the depot, re-lists to refresh
580	/// facts, reads project_id from the `<moniker>.depot-project` fact file, and
581	/// cross-checks it against the RBDC compose derivation. The moniker survives
582	/// in rbrr.env for cases 3 and 4.
583	fn rbtdrp_depot_stand_up(dir: &Path) -> rbtdre_Verdict {
584	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_stand_up_impl(ctx, dir))
585	}
586	
587	fn rbtdrp_depot_stand_up_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
588	    let root = ctx.project_root().to_path_buf();
589	
590	    if let Err(e) = rbtdrp_install_throwaway_prefixes(&root) {
591	        return rbtdre_Verdict::Fail(format!("install throwaway prefixes: {}", e));
592	    }
593	
594	    let list_pre = match rbtdrp_invoke_logged(
595	        ctx,
596	        RBTDRM_COLOPHON_DEPOT_LIST,
597	        &[],
598	        &[],
599	        dir,
600	        "list-pre",
601	    ) {
602	        Ok(r) => r,
603	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
604	    };
605	    if list_pre.exit_code != 0 {
606	        return rbtdre_Verdict::Fail(format!(
607	            "depot list (pre-levy) exit {}\n{}",
608	            list_pre.exit_code, list_pre.stderr
609	        ));
610	    }
611	
612	    let moniker = match rbtdrp_pick_next_moniker(&list_pre, RBTDRP_FAMILY_STEM_ARC) {
613	        Ok(m) => m,
614	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
615	    };
616	    if let Err(e) = rbtdrp_install_depot_moniker(&root, &moniker) {
617	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
618	    }
619	
620	    let levy = match rbtdrp_invoke_logged(
621	        ctx,
622	        RBTDRM_COLOPHON_DEPOT_LEVY,
623	        &[],
624	        &[],
625	        dir,
626	        "levy",
627	    ) {
628	        Ok(r) => r,
629	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
630	    };
631	    if levy.exit_code != 0 {
632	        return rbtdre_Verdict::Fail(format!(
633	            "depot levy exit {}\n{}",
634	            levy.exit_code, levy.stderr
635	        ));
636	    }
637	
638	    let list_present = match rbtdrp_invoke_logged(
639	        ctx,
640	        RBTDRM_COLOPHON_DEPOT_LIST,
641	        &[],
642	        &[],
643	        dir,
644	        "list-present",
645	    ) {
646	        Ok(r) => r,
647	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
648	    };
649	    if list_present.exit_code != 0 {
650	        return rbtdre_Verdict::Fail(format!(
651	            "depot list (after levy) exit {}\n{}",
652	            list_present.exit_code, list_present.stderr
653	        ));
654	    }
655	
656	    let fact_path = list_present
657	        .burv_output
658	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
659	        .join(format!("{}.{}", moniker, RBTDRP_FACT_EXT_DEPOT_PROJECT));
660	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
661	        Ok(s) => s.trim().to_string(),
662	        Err(e) => {
663	            return rbtdre_Verdict::Fail(format!(
664	                "read depot-project fact '{}': {}",
665	                fact_path.display(),
666	                e
667	            ))
668	        }
669	    };
670	    if fact_project_id.is_empty() {
671	        return rbtdre_Verdict::Fail(format!(
672	            "depot-project fact is empty: {}",
673	            fact_path.display()
674	        ));
675	    }
676	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
677	
678	    let composed_project_id = match rbtdrp_compose_project_id(&root, &moniker) {
679	        Ok(p) => p,
680	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
681	    };
682	    if composed_project_id != fact_project_id {
683	        return rbtdre_Verdict::Fail(format!(
684	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
685	             (RBDC kindle derivation diverged from payor creation)",
686	            composed_project_id, fact_project_id
687	        ));
688	    }
689	
690	    rbtdre_Verdict::Pass
691	}
