694	
695	/// Case 3 — SA cycle. Pre-condition: depot stood up by case 2 (moniker in
696	/// rbrr.env). Mantles governor (RBRA lands in BURV output; copy to canonical),
697	/// then for each role: invest → copy assay → canonical → access-probe.
698	/// Divests both roles in reverse order, verifies BBAAN's
699	/// divest-deletes-production-RBRA contract via canonical-path absence checks.
700	/// Best-effort cleanup of assay file at the end.
701	fn rbtdrp_sa_cycle(dir: &Path) -> rbtdre_Verdict {
702	    rbtdrc_with_ctx(|ctx| rbtdrp_sa_cycle_impl(ctx, dir))
703	}
704	
705	fn rbtdrp_sa_cycle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
706	    let root = ctx.project_root().to_path_buf();
707	
708	    let rbrr = root.join(RBTDRP_RBRR_FILE);
709	    let moniker = match rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_DEPOT_MONIKER) {
710	        Some(m) if !m.is_empty() => m,
711	        _ => {
712	            return rbtdre_Verdict::Fail(
713	                "case 2 (stand-up) did not run or rbrr.env is missing the moniker \
714	                 (RBRR_DEPOT_MONIKER is blank)"
715	                    .to_string(),
716	            )
717	        }
718	    };
719	    let _ = std::fs::write(dir.join("moniker.txt"), &moniker);
720	
721	    let mantle = match rbtdrp_invoke_logged(
722	        ctx,
723	        RBTDRM_COLOPHON_GOV_MANTLE,
724	        &[],
725	        &[],
726	        dir,
727	        "mantle",
728	    ) {
729	        Ok(r) => r,
730	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
731	    };
732	    if mantle.exit_code != 0 {
733	        return rbtdre_Verdict::Fail(format!(
734	            "governor mantle exit {}\n{}",
735	            mantle.exit_code, mantle.stderr
736	        ));
737	    }
738	
739	    let governor_email = match rbtdri_read_burv_fact(&mantle, RBTDRP_FACT_GOVERNOR_SA_EMAIL) {
740	        Ok(s) => s,
741	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
742	    };
743	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &governor_email);
744	
745	    // Mantle deposits governor RBRA into its BURV output dir as
746	    // governor-<timestamp>.rbra; locate and copy to canonical.
747	    let mantle_out_dir = mantle.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
748	    let governor_rbra_src = match std::fs::read_dir(&mantle_out_dir)
749	        .map_err(|e| format!("read mantle output dir {}: {}", mantle_out_dir.display(), e))
750	        .and_then(|entries| {
751	            let matches: Vec<_> = entries
752	                .filter_map(|e| e.ok())
753	                .filter(|e| {
754	                    e.file_name()
755	                        .to_str()
756	                        .map(|n| n.starts_with("governor-") && n.ends_with(".rbra"))
757	                        .unwrap_or(false)
758	                })
759	                .collect();
760	            match matches.len() {
761	                0 => Err("no governor-*.rbra file in mantle BURV output".to_string()),
762	                1 => Ok(matches.into_iter().next().unwrap().path()),
763	                n => Err(format!("{} governor-*.rbra files in mantle BURV output", n)),
764	            }
765	        }) {
766	        Ok(p) => p,
767	        Err(e) => return rbtdre_Verdict::Fail(format!("locate governor RBRA: {}", e)),
768	    };
769	
770	    let governor_canonical = match rbtdrp_canonical_rbra(&root, "governor") {
771	        Ok(p) => p,
772	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
773	    };
774	    if let Some(parent) = governor_canonical.parent() {
775	        if let Err(e) = std::fs::create_dir_all(parent) {
776	            return rbtdre_Verdict::Fail(format!(
777	                "create governor RBRA dir {}: {}",
778	                parent.display(),
779	                e
780	            ));
781	        }
782	    }
783	    if let Err(e) = std::fs::copy(&governor_rbra_src, &governor_canonical) {
784	        return rbtdre_Verdict::Fail(format!(
785	            "copy governor RBRA {} → {}: {}",
786	            governor_rbra_src.display(),
787	            governor_canonical.display(),
788	            e
789	        ));
790	    }
791	    if !governor_canonical.exists() {
792	        return rbtdre_Verdict::Fail(format!(
793	            "governor canonical RBRA absent after copy: {}",
794	            governor_canonical.display()
795	        ));
796	    }
797	
798	    let assay_canonical = match rbtdrp_canonical_rbra(&root, "assay") {
799	        Ok(p) => p,
800	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
801	    };
802	
803	    // Retriever: invest → assay → canonical → access-probe.
804	    let invest_ret = match rbtdrp_invoke_logged(
805	        ctx,
806	        RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
807	        &[RBTDRP_IDENTITY_RETRIEVER],
808	        &[],
809	        dir,
810	        "invest-retriever",
811	    ) {
812	        Ok(r) => r,
813	        Err(e) => return rbtdre_Verdict::Fail(format!("invest retriever: {}", e)),
814	    };
815	    if invest_ret.exit_code != 0 {
816	        return rbtdre_Verdict::Fail(format!(
817	            "invest retriever exit {}\n{}",
818	            invest_ret.exit_code, invest_ret.stderr
819	        ));
820	    }
821	
822	    if !assay_canonical.exists() {
823	        return rbtdre_Verdict::Fail(format!(
824	            "assay RBRA absent after invest-retriever: {}",
825	            assay_canonical.display()
826	        ));
827	    }
828	
829	    let retriever_canonical = match rbtdrp_canonical_rbra(&root, "retriever") {
830	        Ok(p) => p,
831	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical retriever RBRA path: {}", e)),
832	    };
833	    if let Some(parent) = retriever_canonical.parent() {
834	        if let Err(e) = std::fs::create_dir_all(parent) {
835	            return rbtdre_Verdict::Fail(format!(
836	                "create retriever RBRA dir {}: {}",
837	                parent.display(),
838	                e
839	            ));
840	        }
841	    }
842	    if let Err(e) = std::fs::copy(&assay_canonical, &retriever_canonical) {
843	        return rbtdre_Verdict::Fail(format!(
844	            "copy assay RBRA → retriever canonical {}: {}",
845	            retriever_canonical.display(),
846	            e
847	        ));
848	    }
849	
850	    let probe_ret = match rbtdri_invoke_imprint(
851	        ctx,
852	        RBTDRM_COLOPHON_ACCESS_PROBE,
853	        "retriever",
854	        &[],
855	    ) {
856	        Ok(r) => r,
857	        Err(e) => {
858	            return rbtdre_Verdict::Fail(format!("access-probe retriever invocation: {}", e))
859	        }
860	    };
861	    let _ = std::fs::write(dir.join("probe-retriever-stdout.txt"), &probe_ret.stdout);
862	    let _ = std::fs::write(dir.join("probe-retriever-stderr.txt"), &probe_ret.stderr);
863	    if probe_ret.exit_code != 0 {
864	        return rbtdre_Verdict::Fail(format!(
865	            "access-probe retriever exit {}\n{}",
866	            probe_ret.exit_code, probe_ret.stderr
867	        ));
868	    }
869	
870	    // Director: invest → assay → canonical → access-probe.
871	    let invest_dir = match rbtdrp_invoke_logged(
872	        ctx,
873	        RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
874	        &[RBTDRP_IDENTITY_DIRECTOR],
875	        &[],
876	        dir,
877	        "invest-director",
878	    ) {
879	        Ok(r) => r,
880	        Err(e) => return rbtdre_Verdict::Fail(format!("invest director: {}", e)),
881	    };
882	    if invest_dir.exit_code != 0 {
883	        return rbtdre_Verdict::Fail(format!(
884	            "invest director exit {}\n{}",
885	            invest_dir.exit_code, invest_dir.stderr
886	        ));
887	    }
888	
889	    if !assay_canonical.exists() {
890	        return rbtdre_Verdict::Fail(format!(
891	            "assay RBRA absent after invest-director: {}",
892	            assay_canonical.display()
893	        ));
894	    }
895	    let director_canonical = match rbtdrp_canonical_rbra(&root, "director") {
896	        Ok(p) => p,
897	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical director RBRA path: {}", e)),
898	    };
899	    if let Some(parent) = director_canonical.parent() {
900	        if let Err(e) = std::fs::create_dir_all(parent) {
901	            return rbtdre_Verdict::Fail(format!(
902	                "create director RBRA dir {}: {}",
903	                parent.display(),
904	                e
905	            ));
906	        }
907	    }
908	    if let Err(e) = std::fs::copy(&assay_canonical, &director_canonical) {
909	        return rbtdre_Verdict::Fail(format!(
910	            "copy assay RBRA → director canonical {}: {}",
911	            director_canonical.display(),
912	            e
913	        ));
914	    }
915	
916	    let probe_dir = match rbtdri_invoke_imprint(
917	        ctx,
918	        RBTDRM_COLOPHON_ACCESS_PROBE,
919	        "director",
920	        &[],
921	    ) {
922	        Ok(r) => r,
923	        Err(e) => {
924	            return rbtdre_Verdict::Fail(format!("access-probe director invocation: {}", e))
925	        }
926	    };
927	    let _ = std::fs::write(dir.join("probe-director-stdout.txt"), &probe_dir.stdout);
928	    let _ = std::fs::write(dir.join("probe-director-stderr.txt"), &probe_dir.stderr);
929	    if probe_dir.exit_code != 0 {
930	        return rbtdre_Verdict::Fail(format!(
931	            "access-probe director exit {}\n{}",
932	            probe_dir.exit_code, probe_dir.stderr
933	        ));
934	    }
935	
936	    // Divests in reverse order.
937	    let divest_dir = match rbtdrp_invoke_logged(
938	        ctx,
939	        RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
940	        &[RBTDRP_IDENTITY_DIRECTOR],
941	        &[],
942	        dir,
943	        "divest-director",
944	    ) {
945	        Ok(r) => r,
946	        Err(e) => return rbtdre_Verdict::Fail(format!("divest director: {}", e)),
947	    };
948	    if divest_dir.exit_code != 0 {
949	        return rbtdre_Verdict::Fail(format!(
950	            "divest director exit {}\n{}",
951	            divest_dir.exit_code, divest_dir.stderr
952	        ));
953	    }
954	    if director_canonical.exists() {
955	        return rbtdre_Verdict::Fail(format!(
956	            "director canonical RBRA still present after divest: {} \
957	             (BBAAN divest-deletes-production-RBRA contract violated)",
958	            director_canonical.display()
959	        ));
960	    }
961	
962	    let divest_ret = match rbtdrp_invoke_logged(
963	        ctx,
964	        RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
965	        &[RBTDRP_IDENTITY_RETRIEVER],
966	        &[],
967	        dir,
968	        "divest-retriever",
969	    ) {
970	        Ok(r) => r,
971	        Err(e) => return rbtdre_Verdict::Fail(format!("divest retriever: {}", e)),
972	    };
973	    if divest_ret.exit_code != 0 {
974	        return rbtdre_Verdict::Fail(format!(
975	            "divest retriever exit {}\n{}",
976	            divest_ret.exit_code, divest_ret.stderr
977	        ));
978	    }
979	    if retriever_canonical.exists() {
980	        return rbtdre_Verdict::Fail(format!(
981	            "retriever canonical RBRA still present after divest: {} \
982	             (BBAAN divest-deletes-production-RBRA contract violated)",
983	            retriever_canonical.display()
984	        ));
985	    }
986	
987	    if assay_canonical.exists() {
988	        let _ = std::fs::remove_file(&assay_canonical);
989	    }
990	
991	    rbtdre_Verdict::Pass
992	}
993	
994	// ── Case 4: depot tear-down ──────────────────────────────────
995	
996	/// Case 4 — depot tear-down. Pre-condition: depot exists from case 2. Reads
997	/// moniker from rbrr.env, unmakes the depot (BURE_CONFIRM=skip), re-lists,
998	/// and verifies the depot is absent or in DELETE_REQUESTED state via
999	/// fact-file content read (no stdout-grep).
1000	fn rbtdrp_depot_tear_down(dir: &Path) -> rbtdre_Verdict {
1001	    rbtdrc_with_ctx(|ctx| rbtdrp_depot_tear_down_impl(ctx, dir))
1002	}
1003	
1004	fn rbtdrp_depot_tear_down_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
1005	    let root = ctx.project_root().to_path_buf();
1006	
1007	    let rbrr = root.join(RBTDRP_RBRR_FILE);
1008	    let moniker = match rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_DEPOT_MONIKER) {
1009	        Some(m) if !m.is_empty() => m,
1010	        _ => {
1011	            return rbtdre_Verdict::Fail(
1012	                "case 2 (stand-up) did not run or rbrr.env is missing the moniker \
1013	                 (RBRR_DEPOT_MONIKER is blank)"
1014	                    .to_string(),
1015	            )
1016	        }
1017	    };
1018	
1019	    let project_id = match rbtdrp_compose_project_id(&root, &moniker) {
1020	        Ok(p) => p,
1021	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
1022	    };
1023	    let _ = std::fs::write(dir.join("project-id.txt"), &project_id);
1024	
1025	    let unmake = match rbtdrp_invoke_logged(
1026	        ctx,
1027	        RBTDRM_COLOPHON_DEPOT_UNMAKE,
1028	        &[],
1029	        &[(RBTDRP_BURE_CONFIRM_KEY, RBTDRP_BURE_CONFIRM_SKIP)],
1030	        dir,
1031	        "unmake",
1032	    ) {
1033	        Ok(r) => r,
1034	        Err(e) => return rbtdre_Verdict::Fail(format!("depot unmake: {}", e)),
1035	    };
1036	    if unmake.exit_code != 0 {
1037	        return rbtdre_Verdict::Fail(format!(
1038	            "depot unmake exit {}\n{}",
1039	            unmake.exit_code, unmake.stderr
1040	        ));
1041	    }
1042	
1043	    let list_after = match rbtdrp_invoke_logged(
1044	        ctx,
1045	        RBTDRM_COLOPHON_DEPOT_LIST,
1046	        &[],
1047	        &[],
1048	        dir,
1049	        "list-after",
1050	    ) {
1051	        Ok(r) => r,
1052	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after unmake): {}", e)),
1053	    };
1054	    if list_after.exit_code != 0 {
1055	        return rbtdre_Verdict::Fail(format!(
1056	            "depot list (after unmake) exit {}\n{}",
1057	            list_after.exit_code, list_after.stderr
1058	        ));
1059	    }
1060	
1061	    let depot_fact_path = list_after
1062	        .burv_output
1063	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
1064	        .join(format!("{}.{}", moniker, RBTDRP_FACT_EXT_DEPOT));
1065	
1066	    if !depot_fact_path.exists() {
1067	        return rbtdre_Verdict::Pass;
1068	    }
1069	
1070	    let depot_state = match std::fs::read_to_string(&depot_fact_path) {
1071	        Ok(s) => s.trim().to_string(),
1072	        Err(e) => {
1073	            return rbtdre_Verdict::Fail(format!(
1074	                "read depot fact '{}': {}",
1075	                depot_fact_path.display(),
1076	                e
1077	            ))
1078	        }
1079	    };
1080	
1081	    if depot_state == RBTDRP_DELETE_REQUESTED {
1082	        return rbtdre_Verdict::Pass;
1083	    }
1084	
1085	    rbtdre_Verdict::Fail(format!(
1086	        "depot '{}' (project '{}') still present with unexpected state '{}' after unmake \
1087	         (expected absent or '{}')",
1088	        moniker, project_id, depot_state, RBTDRP_DELETE_REQUESTED
1089	    ))
1090	}
1091	
1092	// ── Section registry ─────────────────────────────────────────
1093	
1094	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[
1095	    rbtdre_Section {
1096	        name: "pristine-lifecycle-gate",
1097	        cases: &[case!(rbtdrp_marshal_zero_attestation)],
1098	    },
1099	    rbtdre_Section {
1100	        name: "pristine-lifecycle-arc",
1101	        cases: &[
1102	            case!(rbtdrp_depot_stand_up),
1103	            case!(rbtdrp_sa_cycle),
1104	            case!(rbtdrp_depot_tear_down),
1105	        ],
1106	    },
1107	];
1108

